generated_oml:
// ---------- Sensing Components ----------
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) measuring electric current of the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder providing rotor position measurements of the motor."
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox delivering gear output position."
    DTDFVocab:producedData GearboxPositionDataTransmitted
]

// ---------- Data Transmitted ----------
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// ---------- Data ----------
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑stamped motor current trace I_M streamed via MQTT."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkSimulationEngine, FrictionIdentificationEngine
]

instance MotorPositionData : DTDFVocab:Data [
    base:desc "Time‑stamped motor position trace from the motor encoder."
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo SimulinkSimulationEngine, FrictionIdentificationEngine
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Time‑stamped gearbox output position trace from the secondary encoder."
    DTDFVocab:fromData GearboxPositionDataTransmitted
    DTDFVocab:inputTo SimulinkSimulationEngine, FrictionIdentificationEngine
]

// ---------- Models ----------
instance SysMLBlockModel : DTDFVocab:Model [
    base:desc "SysML block‑definition and internal‑block diagrams describing the motor and gearboxes."
    DTDFVocab:inputTo SysMLModelingTool
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "Simulink simulation model of the permanent‑magnet synchronous motor."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkGearwheelModel : DTDFVocab:Model [
    base:desc "Simulink simulation model of the gearwheel."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink simulation model of the cycloidal gearbox."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box Coulomb‑Viscous friction model."
    DTDFVocab:inputTo FrictionIdentificationEngine
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box Stribeck friction model."
    DTDFVocab:inputTo FrictionIdentificationEngine
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box Dahl friction model."
    DTDFVocab:inputTo FrictionIdentificationEngine
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "Analytical white‑box LuGre friction model."
    DTDFVocab:inputTo FrictionIdentificationEngine
]

// ---------- Enablers ----------
instance SimulinkSimulationEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment executing simulation models of motor, gearwheel and gearbox."
    DTDFVocab:enables SimulationComparisonService
]

instance FrictionIdentificationEngine : DTDFVocab:Enabler [
    base:desc "Processing component that continuously identifies static, kinetic and viscous friction parameters from sensor data."
    DTDFVocab:enables ContinuousFrictionIdentificationService, UpdatedFrictionModelGenerationService
]

instance WebDashboardVisualizationEngine : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualising real‑time friction trends, model deviations and simulation comparisons."
    DTDFVocab:enables RealTimeDashboardVisualizationService
]

instance MqttDataStreamer : DTDFVocab:Enabler [
    base:desc "MQTT broker handling live streaming of sensor data to the digital shadow."
    DTDFVocab:enables DataStreamingService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "AAS implementation providing standardized data exchange between the robot and its digital shadow."
    DTDFVocab:enables AASIntegrationService
]

instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML tooling used to create block‑definition and internal‑block diagrams of motor and gearboxes."
    DTDFVocab:enables ModelingSupportService
]

// ---------- Services ----------
instance SimulationComparisonService : DTDFVocab:Service [
    base:desc "Compares simulated data from Simulink models with measured sensor data."
    DTDFVocab:provides ModelDeviationInsight
]

instance UpdatedFrictionModelGenerationService : DTDFVocab:Service [
    base:desc "Generates updated friction model parameters and feeds them back to the robot controller."
    DTDFVocab:provides UpdateRobotControllerAction
]

instance ContinuousFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuously identifies static, kinetic and viscous friction parameters from incoming data."
    DTDFVocab:provides FrictionTrendInsight
]

instance RealTimeDashboardVisualizationService : DTDFVocab:Service [
    base:desc "Provides operators with real‑time visualisation of friction trends and model deviations on the dashboard."
    DTDFVocab:provides FrictionTrendInsight, ModelDeviationInsight
]

instance DataStreamingService : DTDFVocab:Service [
    base:desc "Streams live sensor data via MQTT to the digital shadow."
    DTDFVocab:provides LiveDataInsight
]

instance AASIntegrationService : DTDFVocab:Service [
    base:desc "Manages standardized data exchange using the Asset Administration Shell."
    DTDFVocab:provides AASDataInsight
]

instance ModelingSupportService : DTDFVocab:Service [
    base:desc "Supports creation and maintenance of SysML models."
    DTDFVocab:provides ModelingInsight
]

// ---------- Insights ----------
instance FrictionTrendInsight : DTDFVocab:Insight [
    base:desc "Insight into friction trends derived from continuous identification."
]

instance ModelDeviationInsight : DTDFVocab:Insight [
    base:desc "Insight into deviations between simulated and measured models."
]

instance LiveDataInsight : DTDFVocab:Insight [
    base:desc "Insight that live sensor data are successfully streamed to the shadow."
]

instance AASDataInsight : DTDFVocab:Insight [
    base:desc "Insight that data exchange via AAS is operational."
]

instance ModelingInsight : DTDFVocab:Insight [
    base:desc "Insight that SysML models accurately reflect the physical motor and gearboxes."
]

// ---------- Actions ----------
instance UpdateRobotControllerAction : DTDFVocab:Action [
    base:desc "Feeds back derived friction parameters to the robot controller to improve motion accuracy."
    DTDFVocab:IsAutomatic true
]

// ---------- Digital Twin Component ----------
instance FrictionShadow : DTDFVocab:Component [
    base:desc "Passive digital shadow (FrictionShadow) representing the first vertical axis (AX1) of the MABI MAX 100 robot."
    base:contains MotorCurrentSensor, MotorEncoderSensor, GearboxEncoderSensor,
                 SimulinkSimulationEngine, FrictionIdentificationEngine, WebDashboardVisualizationEngine,
                 MqttDataStreamer, AssetAdministrationShell, SysMLModelingTool
]

instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:contains FrictionShadow
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow does not transmit data or commands back to the physical robot."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time (continuous) data acquisition and model update during robot operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The asset (first axis) provides sensor streams to the processing component; the processing component executes Simulink simulation and friction models, producing simulated data traces; both measured and simulated traces are stored in the digital shadow (FrictionShadow) and visualised in a dashboard; all communication follows the digital shadow reference model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operative stage – the shadow is created and used while the robot is running to support online friction identification."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of each DataPoint to its source and processing model; validation by comparing simulated torque/velocity against measured data; use of both white‑box analytical and black‑box data‑driven friction models to capture different fidelity levels; parameters are updated continuously to reflect wear and temperature effects."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol is used for publishing sensor streams from the robot to the digital shadow; data are organised as DataTraces within the shadow."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of the Asset Administration Shell (AAS) standard and SysML, both established Industry 4.0 and MBSE standards."
]
